@KafkaListener(topics = "notification-events")
public void process(NotificationEvent event) {
    UserPreferences prefs = prefCache.get(event.getUserId());

    String idemKey = DigestUtils.sha256Hex(
        event.getUserId() + event.getTemplateId() + 
        event.getWindowMinute());

    if (prefs.isPushEnabled(event.getCategory())) {
        kafkaTemplate.send("push-notifications",
            new PushTask(event, idemKey));
    }
    if (prefs.isEmailEnabled(event.getCategory())) {
        kafkaTemplate.send("email-notifications",
            new EmailTask(event, idemKey));
    }
}

public void sendBatch(List<String> tokens, Notification notification) {
    MulticastMessage message = MulticastMessage.builder()
        .addAllTokens(tokens)
        .setNotification(notification)
        .build();

    BatchResponse response = FirebaseMessaging.getInstance().sendMulticast(message);

    IntStream.range(0, response.getResponses().size())
        .filter(i -> !response.getResponses().get(i).isSuccessful())
        .forEach(i -> {
            String errorCode = response.getResponses().get(i).getException().getMessagingErrorCode().name();
            if ("UNREGISTERED".equals(errorCode)) {
                tokenRepo.delete(tokens.get(i));
            }
        });
}
